module.render:
const def = (v, d) => (v === undefined || v === '') ? d : v;
const variant = String(def(args.variant, 'outline')).toLowerCase();
const color = def(args.color, 'var(--accent-color)');
const bw = def(args.borderwidth, '3');
const radius = def(args.radius, '8');
const align = String(def(args.align, 'left')).toLowerCase();
const title = (args.title || '').trim();
const icon = (args.icon || '').trim();
const textcolor = (args.textcolor || '').trim();
const background = (args.background || '').trim();
const shadow = !(String(args.shadow).toLowerCase() === 'false' || String(args.shadow) === '0');
const bodyStr = sections[0] ? sections[0].trim() : '';

const vars = [
  '--cl-color: ' + color,
  '--cl-bw: ' + bw + 'px',
  '--cl-radius: ' + radius + 'px',
  '--cl-align: ' + align,
];
if (textcolor) vars.push('--cl-text: ' + textcolor);
if (background) vars.push('--cl-bg: ' + background);

const cls = ['mdp-mod-callout', 'mdp-mod-callout--' + variant];
if (shadow) cls.push('mdp-mod-callout--shadow');

const head = (title || icon)
  ? '<div class="mdp-mod-callout-title">'
      + (icon ? '<span class="mdp-mod-callout-icon">' + icon + '</span>' : '')
      + (title ? '<span>' + title + '</span>' : '')
    + '</div>'
  : '';

return '\n\n<div class="' + cls.join(' ') + '" style="' + vars.join('; ') + ';">'
  + head
  + '<div class="mdp-mod-callout-body">\n\n' + bodyStr + '\n\n</div></div>\n\n';
